"use client";

import { useState } from "react";
import {
  LayoutDashboard,
  Package,
  Search,
  ClipboardCheck,
  Users,
  Menu,
} from "lucide-react";
import Link from "next/link";

export default function AdminLayout({ children }) {
  const [isOpen, setIsOpen] = useState(true);

  const menuItems = [
    { id: "dashboard", label: "Dashboard", icon: LayoutDashboard, href: "/admin/dashboard" },
    { id: "lost", label: "Lost Items", icon: Package, href: "/item" },
    { id: "found", label: "Found Items", icon: Search, href: "/item" },
    { id: "claims", label: "Claims", icon: ClipboardCheck, href: "/admin/claimsreview" },
    { id: "users", label: "Users", icon: Users, href: "/admin/users" },
  ];

  return (
    <div className="flex min-h-screen bg-[#F9F8F6]">

      {/* Sidebar */}
      <aside
        className={`shadow-md transition-all duration-300 border-r 
          bg-indigo-800 text-white
          ${isOpen ? "w-64" : "w-16"}
        `}
      >
        {/* Top Section */}
        <div className="flex items-center justify-between p-4 border-b border-indigo-500">
          <h1
            className={`font-bold text-lg transition-all duration-200
              ${isOpen ? "opacity-100" : "opacity-0 w-0"}
            `}
          >
            Admin Panel
          </h1>

          {/* Toggle Button */}
          <button onClick={() => setIsOpen(!isOpen)}>
            <Menu className="w-6 h-6 text-white" />
          </button>
        </div>

        {/* Menu Items */}
        <nav className="mt-4">
          {menuItems.map((item) => (
            <Link key={item.id} href={item.href}>
              <div className="flex items-center p-4 cursor-pointer 
                hover:bg-indigo-700 transition
              ">
                <item.icon className="w-5 h-5 text-white" />

                <span
                  className={`ml-3 font-medium transition-all duration-200
                    ${isOpen ? "opacity-100" : "opacity-0 w-0 hidden"}
                  `}
                >
                  {item.label}
                </span>
              </div>
            </Link>
          ))}
        </nav>
      </aside>

      {/* Main Content */}
      <main className="flex-1 p-6 text-gray-900">{children}</main>
    </div>
  );
}
